class LRUCache {
  constructor(capacity) {
    this.capacity = capacity;
    this.cache = [];
  }

  get(key) {
    let foundIndex = -1;
    for (let index = 0; index < this.cache.length; index++) {
      if (this.cache[index].key === key) {
        foundIndex = index;
        break;
      }
    }

    if (foundIndex === -1) {
      return -1;
    }

    // Move the accessed item to the front to mark it as most recently used.

    const foundItem = this.cache.splice(foundIndex, 1)[0];
    this.cache.unshift(foundItem);

    return foundItem.value;
  }

  put(key, value) {
    let existingItemIndex = -1;
    for (let index = 0; index < this.cache.length; index++) {
      if (this.cache[index].key === key) {
        existingItemIndex = index;
        break;
      }
    }

    if (existingItemIndex !== -1) {
      // This key already exists, so we just update its value and move it to the front.

      const existingItem = this.cache.splice(existingItemIndex, 1)[0];
      existingItem.value = value;
      this.cache.unshift(existingItem);
    } else {
      if (this.cache.length >= this.capacity) {
        // The cache is full, so we must remove the last item, which is the least recently used.

        this.cache.pop();
      }

      // Add the new item to the front of the line as it's the most recently used.

      this.cache.unshift({ key: key, value: value });
    }
  }
}

