                foundItem = cacheItems.get(index);
                foundIndex = index;
                break;
            }
        }

        if (foundItem != null) {
            // To mark an item as recently used, we must move it to the front of the list.

            cacheItems.remove(foundIndex);
            cacheItems.add(0, foundItem);
            return foundItem.value;
        }

        return -1;
    }

    public void put(int key, int value) {
        Pair foundItem = null;
        int foundIndex = -1;

