class LRUCache {
private:
    int cache_capacity;
    std::vector<std::pair<int, int>> cache_items;

public:
    LRUCache(int capacity) {
        this->cache_capacity = capacity;
    }

    int get(int key) {
        // Iterate through all items to find the requested key.
        for (auto iterator = cache_items.begin(); iterator != cache_items.end(); ++iterator) {
            if (iterator->first == key) {
                std::pair<int, int> found_item = *iterator;
                cache_items.erase(iterator);
                cache_items.insert(cache_items.begin(), found_item);
                return found_item.second;
            }
        }
        return -1;
    }

    void put(int key, int value) {
        // Search for the key to determine if this is an update or a new insertion.
        for (auto iterator = cache_items.begin(); iterator != cache_items.end(); ++iterator) {
            if (iterator->first == key) {
                cache_items.erase(iterator);
                cache_items.insert(cache_items.begin(), {key, value});
                return;
            }
        }

        // The cache is full, so we must remove the last element (least recent) before inserting.
        if (cache_items.size() >= cache_capacity) {
            cache_items.pop_back();
        }

        // The new item is placed at the front to mark it as the most recently used item.
        cache_items.insert(cache_items.begin(), {key, value});
    }
};

