func (this *LRUCache) Get(key int) int {
	var foundItemIndex int = -1
	var foundItem LRUCacheItem

	for itemIndex, currentItem := range this.items {
		if currentItem.key == key {
			foundItemIndex = itemIndex
			foundItem = currentItem
			break
		}
	}

	if foundItemIndex == -1 {
		return -1
	}

	// To mark an item as recently used, we must move it to the front of the list.

	this.items = append(this.items[:foundItemIndex], this.items[foundItemIndex+1:]...)
	this.items = append([]LRUCacheItem{foundItem}, this.items...)

	return foundItem.value
}

func (this *LRUCache) Put(key int, value int) {
	var existingItemIndex int = -1

	for itemIndex, currentItem := range this.items {
		if currentItem.key == key {
			existingItemIndex = itemIndex
			break
		}
	}

	if existingItemIndex != -1 {
		// If the item exists, we remove it from its current position to re-insert it at the front.

		this.items = append(this.items[:existingItemIndex], this.items[existingItemIndex+1:]...)
	} else if len(this.items) == this.capacity {
		// If the cache is full, we remove the last item, which is the least recently used.

		this.items = this.items[:len(this.items)-1]
	}

	newItem := LRUCacheItem{key: key, value: value}
	// Placing the new or updated item at the very front marks it as the most recently used.

	this.items = append([]LRUCacheItem{newItem}, this.items...)
}

