        BruteForceLruCache {
            capacity: capacity as usize,
            items: Vec::new(),
        }
    }

    fn get(&mut self, key: i32) -> i32 {
        let mut found_item_index: Option<usize> = None;
        for (index, &(item_key, _)) in self.items.iter().enumerate() {
            if item_key == key {
                found_item_index = Some(index);
                break;
            }
        }

        if let Some(item_index) = found_item_index {
            // To mark an item as recently used, we must move it to the front of the list.

            let item = self.items.remove(item_index);
            self.items.insert(0, item);
            return item.1;
        }

        -1
    }

    fn put(&mut self, key: i32, value: i32) {
        let mut found_item_index: Option<usize> = None;
        for (index, &(item_key, _)) in self.items.iter().enumerate() {
            if item_key == key {
                found_item_index = Some(index);
                break;
            }
        }

        if let Some(item_index) = found_item_index {
            // If the key already exists, we remove it to re-insert it at the front with the new value.

            self.items.remove(item_index);
