class LRUCache {
  constructor(capacity) {
    this.cache_capacity = capacity;
    this.quick_access_directory = new Map();
    this.head = new Node(-1, -1);
    this.tail = new Node(-1, -1);
    this.head.next = this.tail;
    this.tail.previous = this.head;
  }

  _remove_node(node_to_remove) {
    let previous_node = node_to_remove.previous;
    let next_node = node_to_remove.next;
    previous_node.next = next_node;
    next_node.previous = previous_node;
  }

  _add_to_front(node_to_add) {
    node_to_add.previous = this.head;
    node_to_add.next = this.head.next;
    this.head.next.previous = node_to_add;
    this.head.next = node_to_add;
  }

  get(key_to_find) {
    if (this.quick_access_directory.has(key_to_find)) {
      let found_node = this.quick_access_directory.get(key_to_find);
      // Moving the accessed node to the front marks it as the most recently used.

      this._remove_node(found_node);
      this._add_to_front(found_node);
      return found_node.value;
    }
    return -1;
  }

  put(key_to_add, value_to_add) {
    if (this.quick_access_directory.has(key_to_add)) {
      let existing_node = this.quick_access_directory.get(key_to_add);
      existing_node.value = value_to_add;
      // Updating an existing item also counts as usage, so we move it to the front.

      this._remove_node(existing_node);
      this._add_to_front(existing_node);
    } else {
      // Before adding a new item, we must check if the cache has exceeded its capacity.

      if (this.quick_access_directory.size >= this.cache_capacity) {
        let least_recent_node = this.tail.previous;
        this._remove_node(least_recent_node);
        this.quick_access_directory.delete(least_recent_node.key);
      }
      let new_node = new Node(key_to_add, value_to_add);
      this._add_to_front(new_node);
      this.quick_access_directory.set(key_to_add, new_node);
    }
  }
}

