class LRUCache {
  private readonly capacity: number;
  private cacheDirectory: Map<number, CacheNode> = new Map();
  private head: CacheNode;
  private tail: CacheNode;

  constructor(capacity: number) {
    this.capacity = capacity;
    this.head = new CacheNode(-1, -1); // Sentinel head node
    this.tail = new CacheNode(-1, -1); // Sentinel tail node
    this.head.nextNode = this.tail;
    this.tail.previousNode = this.head;
  }

  private removeNode(nodeToRemove: CacheNode): void {
    const previousNode = nodeToRemove.previousNode!;
    const nextNode = nodeToRemove.nextNode!;
    previousNode.nextNode = nextNode;
    nextNode.previousNode = previousNode;
  }

  private addNodeToFront(nodeToAdd: CacheNode): void {
    nodeToAdd.nextNode = this.head.nextNode;
    nodeToAdd.previousNode = this.head;
    this.head.nextNode!.previousNode = nodeToAdd;
    this.head.nextNode = nodeToAdd;
  }

  get(key: number): number {
    if (this.cacheDirectory.has(key)) {
      const existingNode = this.cacheDirectory.get(key)!;
      // Moving this node to the front marks it as the most recently used item.

      this.removeNode(existingNode);
      this.addNodeToFront(existingNode);
      return existingNode.value;
    }
    return -1;
  }

  put(key: number, value: number): void {
    if (this.cacheDirectory.has(key)) {
      const existingNode = this.cacheDirectory.get(key)!;
      existingNode.value = value;
      // Update usage order even when just updating the value of an existing key.

      this.removeNode(existingNode);
      this.addNodeToFront(existingNode);
    } else {
      // Eviction policy is triggered only when adding a new item to a full cache.

      if (this.cacheDirectory.size === this.capacity) {
        const leastRecentNode = this.tail.previousNode!;
        this.removeNode(leastRecentNode);
        this.cacheDirectory.delete(leastRecentNode.key);
      }
      const newNode = new CacheNode(key, value);
      this.cacheDirectory.set(key, newNode);
      // A new item is always the most recently used, so it goes to the front.

      this.addNodeToFront(newNode);
    }
  }
}

