class LRUCache {
    private final java.util.Map<Integer, DoublyLinkedNode> cacheMap;
    private final DoublyLinkedNode headNode;
    private final DoublyLinkedNode tailNode;
    private final int cacheCapacity;

    public LRUCache(int capacity) {
        this.cacheCapacity = capacity;
        this.cacheMap = new java.util.HashMap<>();

        headNode = new DoublyLinkedNode();
        tailNode = new DoublyLinkedNode();

        headNode.nextNode = tailNode;
        tailNode.previousNode = headNode;
    }

    private void addNodeToFront(DoublyLinkedNode node) {
        node.previousNode = headNode;
        node.nextNode = headNode.nextNode;

        headNode.nextNode.previousNode = node;
        headNode.nextNode = node;
    }

    private void removeNode(DoublyLinkedNode node) {
        DoublyLinkedNode previousNode = node.previousNode;
        DoublyLinkedNode nextNode = node.nextNode;

        previousNode.nextNode = nextNode;
        nextNode.previousNode = previousNode;
    }

    private void moveToFront(DoublyLinkedNode node) {
        removeNode(node);
        addNodeToFront(node);
    }

    private DoublyLinkedNode popTail() {
        DoublyLinkedNode leastRecentNode = tailNode.previousNode;
        removeNode(leastRecentNode);
        return leastRecentNode;
    }

    public int get(int key) {
        DoublyLinkedNode foundNode = cacheMap.get(key);

        if (foundNode == null) {
            return -1;
        }

        // Moving this node to the front marks it as the most recently used.

        moveToFront(foundNode);

        return foundNode.value;
    }

    public void put(int key, int value) {
        DoublyLinkedNode existingNode = cacheMap.get(key);

        if (existingNode != null) {
            existingNode.value = value;
            moveToFront(existingNode);
        } else {
            // If the cache is at capacity, we must evict the least recently used item.

            if (cacheMap.size() == cacheCapacity) {
                DoublyLinkedNode leastRecentNode = popTail();
                // The evicted item's key must be removed from the map to maintain consistency.

                cacheMap.remove(leastRecentNode.key);
            }

            DoublyLinkedNode newNode = new DoublyLinkedNode();
            newNode.key = key;
            newNode.value = value;

            // New items are added to the front as they are the most recently used.

            cacheMap.put(key, newNode);
            addNodeToFront(newNode);
        }
    }
}

