        if (cacheDirectory.TryGetValue(key, out DoublyLinkedListNode foundNode)) {
            MoveToFront(foundNode);
            return foundNode.Value;
        }
        return -1;
    }

    public void Put(int key, int value) {
        if (cacheDirectory.TryGetValue(key, out DoublyLinkedListNode existingNode)) {
            existingNode.Value = value;
            MoveToFront(existingNode);
        } else {
            // The cache is full, so we must evict the least recently used item before adding a new one.
            if (cacheDirectory.Count >= capacity) {
                DoublyLinkedListNode leastRecentNode = this.listTail.Previous;
                RemoveNode(leastRecentNode);
                cacheDirectory.Remove(leastRecentNode.Key);
            }
            DoublyLinkedListNode newNode = new DoublyLinkedListNode { Key = key, Value = value };
            cacheDirectory[key] = newNode;
            AddNodeToFront(newNode);
        }
    }

    private void AddNodeToFront(DoublyLinkedListNode nodeToAdd) {
        DoublyLinkedListNode originalFirstNode = this.listHead.Next;
        this.listHead.Next = nodeToAdd;
        nodeToAdd.Previous = this.listHead;
        nodeToAdd.Next = originalFirstNode;
        originalFirstNode.Previous = nodeToAdd;
    }

    private void RemoveNode(DoublyLinkedListNode nodeToRemove) {
        DoublyLinkedListNode previousNode = nodeToRemove.Previous;
        DoublyLinkedListNode nextNode = nodeToRemove.Next;
        previousNode.Next = nextNode;
        nextNode.Previous = previousNode;
    }

    private void MoveToFront(DoublyLinkedListNode nodeToMove) {
        // To mark an item as recently used, we reposition it to the front of the usage line.

        RemoveNode(nodeToMove);
        AddNodeToFront(nodeToMove);
    }
}

