        capacity:            capacity,
        quickAccessDirectory: make(map[int]*list.Element),
        usageHistoryLine:    list.New(),
    }
}

func (this *LRUCache) Get(key int) int {
    listNode, exists := this.quickAccessDirectory[key]

    if !exists {
        return -1
    }

    // Move the accessed node to the front to mark it as most recently used.

    this.usageHistoryLine.MoveToFront(listNode)
    return listNode.Value.(*Node).value
}

func (this *LRUCache) Put(key int, value int) {
    if listNode, exists := this.quickAccessDirectory[key]; exists {
        // Update the value and move it to the front as it's the most recently used item.

        this.usageHistoryLine.MoveToFront(listNode)
        listNode.Value.(*Node).value = value
        return
    }

    // If the cache is full, we must remove the least recently used item to make space.

    if this.usageHistoryLine.Len() == this.capacity {
        leastRecentlyUsedNode := this.usageHistoryLine.Back()
        if leastRecentlyUsedNode != nil {
            this.usageHistoryLine.Remove(leastRecentlyUsedNode)
            delete(this.quickAccessDirectory, leastRecentlyUsedNode.Value.(*Node).key)
        }
    }

    // Add the new item to the front of the line and record it in our directory.

    newNode := &Node{key: key, value: value}
    elementInList := this.usageHistoryLine.PushFront(newNode)
    this.quickAccessDirectory[key] = elementInList
