    value: i32,
    previous_node: Option<Rc<RefCell<Node>>>,
    next_node: Option<Rc<RefCell<Node>>>,
}

impl Node {
    fn new(key: i32, value: i32) -> Rc<RefCell<Node>> {
        Rc::new(RefCell::new(Node {
            key,
            value,
            previous_node: None,
            next_node: None,
        }))
    }
}

struct LRUCache {
    capacity: usize,
    lookup_directory: HashMap<i32, Rc<RefCell<Node>>>,
    head_sentinel: Rc<RefCell<Node>>,
    tail_sentinel: Rc<RefCell<Node>>,
}

impl LRUCache {
    fn new(capacity: i32) -> Self {
        let head_node = Node::new(-1, -1);
        let tail_node = Node::new(-1, -1);
        head_node.borrow_mut().next_node = Some(Rc::clone(&tail_node));
        tail_node.borrow_mut().previous_node = Some(Rc::clone(&head_node));

        LRUCache {
            capacity: capacity as usize,
            lookup_directory: HashMap::new(),
            head_sentinel: head_node,
            tail_sentinel: tail_node,
        }
    }

    fn move_to_front(&mut self, node_to_move: Rc<RefCell<Node>>) {
        let previous = node_to_move.borrow().previous_node.clone().unwrap();
        let next = node_to_move.borrow().next_node.clone().unwrap();
        previous.borrow_mut().next_node = Some(next.clone());
        next.borrow_mut().previous_node = Some(previous);

        let original_first = self.head_sentinel.borrow().next_node.clone().unwrap();
        self.head_sentinel.borrow_mut().next_node = Some(node_to_move.clone());
        node_to_move.borrow_mut().previous_node = Some(self.head_sentinel.clone());
        node_to_move.borrow_mut().next_node = Some(original_first.clone());
        original_first.borrow_mut().previous_node = Some(node_to_move);
    }

    fn get(&mut self, key: i32) -> i32 {
        if let Some(node) = self.lookup_directory.get(&key) {
            let value = node.borrow().value;
            // Moving the accessed item to the front marks it as most recently used.

            self.move_to_front(Rc::clone(node));
            value
        } else {
            -1
        }
    }

    fn put(&mut self, key: i32, value: i32) {
        if let Some(existing_node) = self.lookup_directory.get(&key) {
            existing_node.borrow_mut().value = value;
            self.move_to_front(Rc::clone(existing_node));
            return;
        }

        // Eviction is necessary when capacity is reached to make space for the new item.

        if self.lookup_directory.len() == self.capacity {
            let least_recent_node = self.tail_sentinel.borrow().previous_node.clone().unwrap();
            let least_recent_key = least_recent_node.borrow().key;
            let new_last_node = least_recent_node.borrow().previous_node.clone().unwrap();

            new_last_node.borrow_mut().next_node = Some(self.tail_sentinel.clone());
            self.tail_sentinel.borrow_mut().previous_node = Some(new_last_node);
            self.lookup_directory.remove(&least_recent_key);
        }

        let new_node = Node::new(key, value);
        self.lookup_directory.insert(key, new_node.clone());

        // The new node is placed at the front, as it is the most recently used item.

        let first_node = self.head_sentinel.borrow().next_node.clone().unwrap();
        self.head_sentinel.borrow_mut().next_node = Some(new_node.clone());
        new_node.borrow_mut().previous_node = Some(self.head_sentinel.clone());
        new_node.borrow_mut().next_node = Some(first_node.clone());
        first_node.borrow_mut().previous_node = Some(new_node);
    }
}

