class Node(var key: Int, var value: Int) {
    var previous: Node? = null
    var next: Node? = null
}

class LRUCache(private val capacity: Int) {
    private val cacheDirectory = mutableMapOf<Int, Node>()
    private var head: Node? = null
    private var tail: Node? = null

    fun get(key: Int): Int {
        val foundNode = cacheDirectory[key]
        return if (foundNode != null) {
            moveToFront(foundNode)
            foundNode.value
        } else {
            -1
        }
    }

    fun put(key: Int, value: Int) {
        val existingNode = cacheDirectory[key]
        if (existingNode != null) {
            existingNode.value = value
            moveToFront(existingNode)
        } else {
            val newNode = Node(key, value)
            if (cacheDirectory.size >= capacity) {
                // Evict the least recently used item from the back to make space for the new one.

                val leastRecentNode = tail
                if (leastRecentNode != null) {
                    cacheDirectory.remove(leastRecentNode.key)
                    removeNode(leastRecentNode)
                }
            }
            addFirst(newNode)
            cacheDirectory[key] = newNode
        }
    }

    private fun moveToFront(nodeToMove: Node) {
        removeNode(nodeToMove)
        addFirst(nodeToMove)
    }

    private fun removeNode(nodeToRemove: Node) {
        val previousNode = nodeToRemove.previous
        val nextNode = nodeToRemove.next

        if (previousNode != null) {
            previousNode.next = nextNode
        } else {
            // Removing the head requires updating the head pointer to the next node.

            head = nextNode
        }

        if (nextNode != null) {
            nextNode.previous = previousNode
        } else {
            // If the removed node was the tail, the new tail is its previous node.

            tail = previousNode
        }
    }

    private fun addFirst(nodeToAdd: Node) {
        nodeToAdd.next = head
        nodeToAdd.previous = null

        if (head != null) {
            head?.previous = nodeToAdd
        }
        head = nodeToAdd

        // If the list was empty, the new node is both the head and the tail.

        if (tail == null) {
            tail = head
        }
    }
}

