class LRUCache {
    private let capacity: Int
    private var cacheDirectory: [Int: Node]
    private var head: Node
    private var tail: Node

    init(_ capacity: Int) {
        self.capacity = capacity
        self.cacheDirectory = [:]
        self.head = Node(key: -1, value: -1) // Sentinel nodes
        self.tail = Node(key: -1, value: -1)
        head.next = tail
        tail.prev = head
    }

    func get(_ key: Int) -> Int {
        if let existingNode = cacheDirectory[key] {
            // Move the accessed node to the front to mark it as most recently used.

            moveToFront(existingNode)
            return existingNode.value
        }
        return -1
    }

    func put(_ key: Int, _ value: Int) {
        if let existingNode = cacheDirectory[key] {
            existingNode.value = value
            moveToFront(existingNode)
        } else {
            // The cache must not exceed its capacity, so we remove the least used item if full.

            if cacheDirectory.count == capacity {
                if let leastRecentNode = tail.prev {
                    removeNode(leastRecentNode)
                    cacheDirectory[leastRecentNode.key] = nil
                }
            }

            let newNode = Node(key: key, value: value)
            cacheDirectory[key] = newNode
            addNodeToFront(newNode)
        }
    }

    private func addNodeToFront(_ nodeToAdd: Node) {
        nodeToAdd.prev = head
        nodeToAdd.next = head.next
        head.next?.prev = nodeToAdd
        head.next = nodeToAdd
    }

    private func removeNode(_ nodeToRemove: Node) {
        let previousNode = nodeToRemove.prev
        let nextNode = nodeToRemove.next
        previousNode?.next = nextNode
        nextNode?.prev = previousNode
    }

    private func moveToFront(_ nodeToMove: Node) {
        // This combined action ensures the node's usage is correctly updated in the list.

        removeNode(nodeToMove)
        addNodeToFront(nodeToMove)
    }
}

