class LRUCache
  attr_reader :capacity

  def initialize(capacity_value)
    @capacity = capacity_value
    @cache_map = {}
    # The head and tail sentinels simplify list manipulation by removing edge cases for an empty list.

    @head_sentinel = Node.new(nil, nil)
    @tail_sentinel = Node.new(nil, nil)
    @head_sentinel.next_node = @tail_sentinel
    @tail_sentinel.prev_node = @head_sentinel
  end

  def get(key_to_find)
    node_to_get = @cache_map[key_to_find]
    return -1 unless node_to_get

    move_to_front(node_to_get)
    node_to_get.value
  end

  def put(key_to_put, value_to_put)
    existing_node = @cache_map[key_to_put]

    if existing_node
      existing_node.value = value_to_put
      move_to_front(existing_node)
    else
      # We must evict the least recently used item to make space before adding the new item.

      if @cache_map.size >= @capacity
        least_recent_node = @tail_sentinel.prev_node
        remove_node(least_recent_node)
        @cache_map.delete(least_recent_node.key)
      end

      new_node = Node.new(key_to_put, value_to_put)
      add_to_front(new_node)
      @cache_map[key_to_put] = new_node
    end
  end

  private

  class Node
    attr_accessor :key, :value, :prev_node, :next_node

    def initialize(key, value)
      @key = key
      @value = value
      @prev_node = nil
      @next_node = nil
    end
  end

  def add_to_front(node_to_add)
    # Placing the node at the front (after the head) marks it as the most recently used.

    original_first_node = @head_sentinel.next_node
    @head_sentinel.next_node = node_to_add
    node_to_add.prev_node = @head_sentinel
    node_to_add.next_node = original_first_node
    original_first_node.prev_node = node_to_add
  end

  def remove_node(node_to_remove)
    previous_node = node_to_remove.prev_node
    next_node = node_to_remove.next_node
    previous_node.next_node = next_node
    next_node.prev_node = previous_node
  end

  def move_to_front(node_to_move)
    # Moving a node to the front requires removing it and then re-adding it to the most recent position.

    remove_node(node_to_move)
    add_to_front(node_to_move)
  end
end
